import base64
import sys

data = """<trimmed-for-brevity>"""

# Using the literal string from the message to be sure
# Actually, the user provided a very long string. I'll just try to decode it.
try:
    with open("final_qr.png", "wb") as f:
        f.write(base64.b64decode(data))
    print("Success")
except Exception as e:
    print(f"Error: {e}")
